// Validate required input fields for skincare analysis
// Supports both direct test payloads and Replit trigger-analysis payloads (price vs priceUsd)
const raw = $input.first().json;
const input = raw.body || raw;

// Normalize price field (Replit sends 'price', tests send 'priceUsd')
const priceUsd = input.priceUsd !== undefined ? input.priceUsd : input.price;

const errors = [];
if (!input.productId) errors.push('productId required');
if (!input.productName && !input.name) errors.push('productName required');
if (!input.brand) errors.push('brand required');
if (priceUsd === undefined || priceUsd === null) errors.push('priceUsd required');
if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join(', '));
}

return [{ json: {
  productId: String(input.productId),
  productName: String(input.productName || input.name),
  brand: String(input.brand),
  category: input.category ? String(input.category) : 'skincare',
  priceUsd: Number(priceUsd),
  ingredientList: input.ingredientList ? String(input.ingredientList) : '',
  website: input.website ? String(input.website) : '',
  description: input.description ? String(input.description) : '',
  runId: input.runId ? String(input.runId) : String(Date.now()),
  // Pass through callback info from Replit trigger
  callbackUrl: input.callbackUrl ? String(input.callbackUrl) : '',
  callbackSecret: input.callbackSecret ? String(input.callbackSecret) : ''
}}];

// Build Stage 1 analysis prompts for all 4 LLMs
const p = $('Validate Input').first().json;
const date = new Date().toISOString().split('T')[0];

const buildPrompt = function(llmName) {
  const s = [];
  s.push('You are the Apex Skincare Intelligence Analyst. Analyze this skincare product as a quality-value coordination game and produce a definitive consumer score. Your analysis determines whether this product delivers genuine value or is built on marketing coordination alone.');
  s.push('');
  s.push('PRODUCT DATA:');
  s.push('- Name: ' + p.productName);
  s.push('- Brand: ' + p.brand);
  s.push('- Category: ' + p.category);
  s.push('- Price: $' + p.priceUsd);
  s.push('- Analysis Date: ' + date);
  s.push('');
  s.push('=== FORMULA DATA (use your knowledge of this product) ===');
  s.push('Research and identify: Full INCI Ingredient List, Key Actives with concentrations, Preservative System, Fragrance Status, Notable Controversial Ingredients.');
  s.push('');
  s.push('=== BRAND POSITIONING ===');
  s.push('Research: Brand Tier (luxury/premium/mid-range/drugstore/indie), Founded/Ownership, Brand Positioning Claim, Primary Marketing Channels, Target Consumer, Price Point vs Category Average.');
  s.push('');
  s.push('=== SCIENTIFIC VALIDATION ===');
  s.push('Research: Clinically Tested (yes/no/claimed), Dermatologist Tested, Third-Party Studies, Key Ingredient Evidence Base (cite PubMed/JAAD where applicable), Claimed Benefits vs Ingredient Reality.');
  s.push('');
  s.push('=== MARKET POSITION ===');
  s.push('Research: Category Rank, Key Competitors at Same Price, What Competitors Offer vs This Product, Dupe Products (same actives, lower price).');
  s.push('');
  s.push('=== COMMUNITY SIGNAL ===');
  s.push('Research: Reddit/skincare community sentiment, Dermatologist/esthetician opinion, Influencer/TikTok signal (organic vs paid), Long-term user reviews (6+ months), Return rate signals.');
  s.push('');
  s.push('=== PRODUCT TYPE CLASSIFICATION ===');
  s.push('MARKETING-LED: Brand/packaging/experience focus, actives secondary, prestige pricing');
  s.push('SCIENCE-LED: Evidence-based formula, actives at clinical concentrations, transparent labeling');
  s.push('HYBRID: Competent formula with significant marketing premium');
  s.push('');
  s.push('=== NARRATIVE CLASSIFICATION (REQUIRED) ===');
  s.push('Primary Category: (moisturizer/serum/cleanser/SPF/treatment/eye cream/oil/toner/mask)');
  s.push('Sub-Category: SPECIFIC function. Examples:');
  s.push('- Serums: Vitamin C, Retinoid, Peptide, Niacinamide, Hyaluronic Acid, AHA/BHA, Growth Factor');
  s.push('- Moisturizers: Barrier Repair, Anti-aging, Hydrating, Oil Control');
  s.push('- Treatments: Acne, Brightening, Redness/Rosacea, Dark Spot, Texture');
  s.push('- SPF: Chemical, Mineral, Hybrid, Tinted');
  s.push('Category Ceiling: Maximum realistic score for the BEST product in this sub-category.');
  s.push('');
  s.push('=== ANALYSIS FRAMEWORK ===');
  s.push('CRITICAL QUESTION: "Is the consumer the exit liquidity?"');
  s.push('NOT "is this brand reputable?" but "will this product quality justify the spend, or is the consumer paying for marketing coordination?"');
  s.push('- If formula genuinely delivers on claims at price -> CONSUMER WINS');
  s.push('- If consumer is paying for brand prestige/influencer coordination over efficacy -> CONSUMER IS EXIT LIQUIDITY');
  s.push('');
  s.push('IGNORE: Packaging aesthetics, celebrity endorsements, brand prestige for its own sake, clean beauty marketing');
  s.push('FOCUS: Do the actives work? Are concentrations effective? Does price reflect formula quality or marketing spend?');
  s.push('');
  s.push('Product Lifecycle Assessment (1-5):');
  s.push('1=Launch (new, limited reviews, high opportunity if formula strong)');
  s.push('2=Growth (cult following forming, organic word-of-mouth, optimal value)');
  s.push('3=Peak (oversaturated social media, premium inflated, dupes proliferating)');
  s.push('4=Saturation (trend declining, cheaper dupes dominate)');
  s.push('5=Forgotten (category declining, discontinuation risk)');
  s.push('');
  s.push('=== SCORING COMPONENTS (100 pts max) ===');
  s.push('');
  s.push('1. INGREDIENT EFFICACY (0-30)');
  s.push('Are key actives clinically validated at or near clinical thresholds?');
  s.push('Cross-reference against JAAD 2025 Delphi consensus and PubMed evidence.');
  s.push('26-30=exceptional (multiple clinically-dosed evidence-grade actives), 20-25=strong, 13-19=moderate, 7-12=weak, 0-6=negligible');
  s.push('');
  s.push('2. SAFETY PROFILE (0-20)');
  s.push('Fragrance: fragrance-free=+4, natural=+1, synthetic=-2, essential oils=-3');
  s.push('Check: irritant load, sensitizers, long-term safety, skin barrier impact');
  s.push('17-20=safe for nearly all, 12-16=generally safe, 7-11=requires care, 0-6=significant concern');
  s.push('');
  s.push('3. VALUE FOR MONEY (0-20)');
  s.push('Compare price to closest formula-equivalent. Check for dupes.');
  s.push('17-20=exceptional value, 12-16=good value, 7-11=fair, 0-6=poor value (brand tax)');
  s.push('');
  s.push('4. FORMULA TRANSPARENCY (0-15)');
  s.push('Full INCI publicly available: +3, Active concentrations disclosed: +4, No proprietary blend: +3, Claims supported by INCI: +3, Consistent formulation: +2');
  s.push('Deductions: proprietary blends=-4, unsupported claims=-3, hidden INCI=-2, silent reformulation=-3');
  s.push('');
  s.push('5. SKIN COMPATIBILITY (0-10)');
  s.push('Sensitive skin suitable: +3, Non-comedogenic: +2, Rosacea safe: +2, Works across skin types: +2, Ophthalmologist tested: +1');
  s.push('');
  s.push('6. SENSORY & USABILITY (0-5)');
  s.push('Appropriate texture: +2, No pilling/residue: +1, Layering compatible: +1, Stable packaging: +1');
  s.push('');
  s.push('=== MODIFIERS ===');
  s.push('Product Lifecycle: 1=Launch:+10to+12 | 2Early:+6to+9 | 2Late:+2to+5 | 3Early:-8to-12 | 3Late:-20to-30 | 4+:-30');
  s.push('Category Heat: Hot+Accelerating+Leader=+12 | +2nd=+8 | Hot+Flat+1st=+5 | Warm+Accel=+3 | Warm+Flat=0 | Cool=-8 | Decel=-15 | Dead=-25');
  s.push('Price Tier: Under$15=+10 | $15-30=+7 | $30-60=+4 | $60-120=+1 | $120-200=0 | $200-400=-6 | $400-800=-12 | Over$800=-18');
  s.push('');
  s.push('=== FINAL SCORE ===');
  s.push('Base Score (sum of 6 components, max 100) + Modifiers = Final Score. Cap at 100, floor at 0.');
  s.push('Tier: S+(85-100), S(75-84), A(65-74), B(50-64), C(<50)');
  s.push('');
  s.push('Return ONLY valid JSON - no markdown, no code fences, no preamble:');
  s.push('{"llm": "' + llmName + '", "stage": 1, "product": "' + p.productName + '", "brand": "' + p.brand + '", "product_type": "<MARKETING-LED|SCIENCE-LED|HYBRID>", "primary_category": "' + p.category + '", "sub_category": "<specific>", "lifecycle_phase": <1-5>, "lifecycle_reasoning": "<why>", "scores": {"ingredient_efficacy": <0-30>, "safety_profile": <0-20>, "value_for_money": <0-20>, "formula_transparency": <0-15>, "skin_compatibility": <0-10>, "sensory_usability": <0-5>}, "modifiers": {"lifecycle": <val>, "category_heat": <val>, "price_tier": <val>}, "base_score": <sum of 6>, "modifier_total": <sum of mods>, "total": <capped 0-100>, "tier": "<S+|S|A|B|C>", "consumer_verdict": "<CONSUMER WINS|CONSUMER IS EXIT LIQUIDITY|NEUTRAL>", "reasoning": "<detailed analysis, minimum 200 words, cite specific ingredients and evidence>", "key_findings": ["<f1>", "<f2>", "<f3>"], "red_flags": ["<concerns or empty>"], "top_competitors": ["<comp1>", "<comp2>"], "best_dupe": "<product+price or null>", "verdict": "<one sentence>"}');
  return s.join('\n');
};

return [{ json: {
  claudeBody: {
    model: 'anthropic/claude-sonnet-4.6',
    max_tokens: 4096,
    messages: [{ role: 'user', content: buildPrompt('Claude Opus 4.5') }]
  },
  gptBody: {
    model: 'openai/gpt-5.4',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst. Return ONLY valid JSON, no markdown fences.' },
      { role: 'user', content: buildPrompt('GPT-5.2') }
    ],
    response_format: { type: 'json_object' }
  },
  geminiBody: {
    model: 'google/gemini-2.5-pro',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst. Return ONLY valid JSON, no markdown fences.' },
      { role: 'user', content: buildPrompt('Gemini 2.5 Pro') }
    ],
    response_format: { type: 'json_object' }
  },
  grokBody: {
    model: 'x-ai/grok-4.20-beta',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst. Return ONLY valid JSON, no markdown fences.' },
      { role: 'user', content: buildPrompt('Grok 4') }
    ],
    response_format: { type: 'json_object' }
  },
  productId: p.productId,
  productName: p.productName,
  brand: p.brand,
  category: p.category,
  priceUsd: p.priceUsd
}}];

// Parse Stage 1 results and build Stage 2 prompts for all 4 LLMs
const items = $input.all();
const product = $('Build S1 Prompts').first().json;

// Extract text from each API response format
// Merge order: Claude(0), GPT(1), Gemini(2), Grok(3)
const extractText = function(item, idx) {
  try {
    const j = item.json;
    if (idx === 0 && j.content && j.content.length > 0) {
      return j.content[0].text;
    }
    if ((idx === 1 || idx === 3) && j.choices && j.choices.length > 0) {
      return j.choices[0].message.content;
    }
    if (idx === 2 && j.candidates && j.candidates.length > 0) {
      return j.candidates[0].content.parts[0].text;
    }
    return JSON.stringify(j);
  } catch (e) {
    return '{"error": "Failed to extract: ' + e.message + '"}';
  }
};

const keys = ['claude', 'gpt', 'gemini', 'grok'];
const labels = { claude: 'Claude', gpt: 'GPT', gemini: 'Gemini', grok: 'Grok' };
const results = {};
for (let i = 0; i < 4; i++) {
  if (i < items.length) {
    results[keys[i]] = extractText(items[i], i);
  } else {
    results[keys[i]] = '{"error": "Model did not respond"}';
  }
}

// Build Stage 2 prompt for each LLM
const buildS2 = function(llmName, ownKey) {
  const s = [];
  s.push('You are the Apex Skincare Intelligence Analyst. You previously analyzed this product independently. Now review your analysis alongside 3 other AI models.');
  s.push('');
  s.push('=== YOUR ORIGINAL ANALYSIS ===');
  s.push(results[ownKey]);
  s.push('');
  s.push('=== OTHER MODELS ANALYSES ===');
  for (const k of keys) {
    if (k !== ownKey) {
      s.push(labels[k] + ': ' + results[k]);
      s.push('');
    }
  }
  s.push('=== DELIBERATION TASK ===');
  s.push('');
  s.push('1. QUICK COMPARISON - Compare all 4 models scores, tiers, phases, consumer verdicts, sub-categories, and category ceilings.');
  s.push('');
  s.push('2. KEY AGREEMENTS (3+ models agree)');
  s.push('');
  s.push('3. KEY DISAGREEMENTS');
  s.push('- Sub-Category Alignment: Did all models classify into the same sub-category? If not, note why.');
  s.push('- If your sub-category differs from 3 other models, reconsider yours.');
  s.push('');
  s.push('4. MISSED INSIGHTS - Did other models identify evidence you missed?');
  s.push('');
  s.push('5. REVISION DECISION');
  s.push('Revise ONLY if: other models identified concrete evidence you missed, strong consensus (3 models) disagrees with your component score by 3+ points, or you made a calculation error.');
  s.push('Do NOT revise just because others scored differently. Stick to your analysis if your reasoning is sound.');
  s.push('');
  s.push('6. HALLUCINATION CHECK');
  s.push('If any model cites an ingredient concentration, study, or claim that cannot be verified -> flag it. Do not propagate unverified statistics.');
  s.push('');
  s.push('=== DATA VERIFICATION RULE ===');
  s.push('Do not cite specific data points from other models unless verifiable. Focus critique on reasoning and methodology.');
  s.push('');
  s.push('=== HARD CONSTRAINTS ===');
  s.push('- revised_total must be between 0 and 100');
  s.push('- base_score = sum of 6 component scores (cannot exceed 100)');
  s.push('- revised_total = base_score + modifier_total (then capped 0-100)');
  s.push('- tier must match revised_total: S+(85-100), S(75-84), A(65-74), B(50-64), C(<50)');
  s.push('- All scores must have exactly 2 decimal places');
  s.push('- If revised_total ends in .00: adjust exactly ONE modifier by +/-0.01 to +/-0.49 based on real nuance');
  s.push('');
  s.push('Return ONLY valid JSON - no markdown, no code fences:');
  s.push('{"llm": "' + llmName + '", "stage": 2, "product": "' + product.productName + '", "brand": "' + product.brand + '", "scores": {"ingredient_efficacy": <0-30>, "safety_profile": <0-20>, "value_for_money": <0-20>, "formula_transparency": <0-15>, "skin_compatibility": <0-10>, "sensory_usability": <0-5>}, "modifiers": {"lifecycle": <val>, "category_heat": <val>, "price_tier": <val>}, "base_score": <sum>, "modifier_total": <sum>, "total": <capped 0-100>, "tier": "<S+|S|A|B|C>", "reasoning": "<refined consensus analysis, minimum 250 words>", "consensus_notes": "<agreements, disagreements, resolutions>", "dimension_rulings": {"ingredient_efficacy": "<range + ruling>", "safety_profile": "<range + ruling>", "value_for_money": "<range + ruling>", "formula_transparency": "<range + ruling>", "skin_compatibility": "<range + ruling>", "sensory_usability": "<range + ruling>"}, "key_findings": ["<f1>", "<f2>", "<f3>"], "red_flags": ["<or empty>"], "hallucinations_flagged": ["<or empty>"], "confidence": "<high|medium|low>", "confidence_reason": "<why>", "consumer_verdict": "<CONSUMER WINS|CONSUMER IS EXIT LIQUIDITY|NEUTRAL>", "verdict": "<one sentence>"}');
  return s.join('\n');
};

return [{ json: {
  claudeBody: {
    model: 'anthropic/claude-sonnet-4.6',
    max_tokens: 4096,
    messages: [{ role: 'user', content: buildS2('Claude Opus 4.5', 'claude') }]
  },
  gptBody: {
    model: 'openai/gpt-5.4',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst doing Stage 2 consensus. Return ONLY valid JSON.' },
      { role: 'user', content: buildS2('GPT-5.2', 'gpt') }
    ],
    response_format: { type: 'json_object' }
  },
  geminiBody: {
    model: 'google/gemini-2.5-pro',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst. Return ONLY valid JSON, no markdown fences.' },
      { role: 'user', content: buildPrompt('Gemini 2.5 Pro') }
    ],
    response_format: { type: 'json_object' }
  },
  grokBody: {
    model: 'x-ai/grok-4.20-beta',
    max_tokens: 4096,
    messages: [
      { role: 'system', content: 'You are the Apex Skincare Intelligence Analyst doing Stage 2 consensus. Return ONLY valid JSON.' },
      { role: 'user', content: buildS2('Grok 4', 'grok') }
    ],
    response_format: { type: 'json_object' }
  },
  stage1Results: results,
  productId: product.productId,
  productName: product.productName,
  brand: product.brand,
  category: product.category,
  priceUsd: product.priceUsd
}}];

// Calculate consensus score from 4 Stage 2 LLM results
const items = $input.all();
const product = $('Build S2 Prompts').first().json;
const stage1Data = product.stage1Results;

// Extract text from each API response
const extractText = function(item, idx) {
  try {
    const j = item.json;
    if (idx === 0 && j.content && j.content.length > 0) return j.content[0].text;
    if ((idx === 1 || idx === 3) && j.choices && j.choices.length > 0) return j.choices[0].message.content;
    if (idx === 2 && j.candidates && j.candidates.length > 0) return j.candidates[0].content.parts[0].text;
    return JSON.stringify(j);
  } catch (e) {
    return '{"error": "' + e.message + '"}';
  }
};

const llmNames = ['Claude Opus 4.5', 'GPT-5.2', 'Gemini 3 Pro', 'Grok 4'];
const stage2Results = [];
const totals = [];

for (let i = 0; i < 4; i++) {
  let parsed = null;
  if (i < items.length) {
    const text = extractText(items[i], i);
    try {
      parsed = JSON.parse(text);
    } catch (e) {
      // Try to extract JSON from text that might have extra content
      try {
        const match = text.match(/\{[\s\S]*\}/);
        if (match) parsed = JSON.parse(match[0]);
      } catch (e2) {
        parsed = { error: 'Failed to parse', raw: text.substring(0, 500), llm: llmNames[i] };
      }
    }
  }
  if (parsed) {
    stage2Results.push(parsed);
    const total = parsed.total !== undefined ? Number(parsed.total) : 0;
    totals.push(total);
  } else {
    stage2Results.push({ error: 'No response', llm: llmNames[i] });
    totals.push(0);
  }
}

// Calculate consensus with outlier weighting
// If any score deviates >15pts from median, weight it at 50%
let consensusScore = 0;
if (totals.length > 0) {
  const sorted = totals.slice().sort(function(a, b) { return a - b; });
  const median = sorted.length % 2 === 0
    ? (sorted[sorted.length / 2 - 1] + sorted[sorted.length / 2]) / 2
    : sorted[Math.floor(sorted.length / 2)];

  let weightedSum = 0;
  let weightTotal = 0;
  for (let i = 0; i < totals.length; i++) {
    const spread = Math.abs(totals[i] - median);
    const weight = spread > 15 ? 0.5 : 1.0;
    weightedSum += totals[i] * weight;
    weightTotal += weight;
  }
  consensusScore = weightTotal > 0 ? Math.round((weightedSum / weightTotal) * 100) / 100 : 0;
}

// Determine tier
let tier = 'C';
if (consensusScore >= 85) tier = 'S+';
else if (consensusScore >= 75) tier = 'S';
else if (consensusScore >= 65) tier = 'A';
else if (consensusScore >= 50) tier = 'B';

// Determine consumer verdict from majority
const verdicts = stage2Results.map(function(r) { return r.consumer_verdict || 'NEUTRAL'; });
const verdictCounts = {};
for (const v of verdicts) {
  verdictCounts[v] = (verdictCounts[v] || 0) + 1;
}
let consumerVerdict = 'NEUTRAL';
let maxCount = 0;
for (const v in verdictCounts) {
  if (verdictCounts[v] > maxCount) {
    maxCount = verdictCounts[v];
    consumerVerdict = v;
  }
}

// Parse Stage 1 results for the callback
const stage1Parsed = {};
const s1keys = ['claude', 'gpt', 'gemini', 'grok'];
for (const k of s1keys) {
  try {
    if (stage1Data && stage1Data[k]) {
      stage1Parsed[k] = JSON.parse(stage1Data[k]);
    }
  } catch (e) {
    stage1Parsed[k] = { raw: stage1Data ? (stage1Data[k] || '').substring(0, 500) : 'missing' };
  }
}

return [{ json: {
  productId: product.productId,
  productName: product.productName,
  brand: product.brand,
  category: product.category,
  priceUsd: product.priceUsd,
  consensusScore: consensusScore,
  tier: tier,
  consumerVerdict: consumerVerdict,
  stage1Results: stage1Parsed,
  stage2Results: stage2Results,
  modelScores: {
    claude: totals[0] || 0,
    gpt: totals[1] || 0,
    gemini: totals[2] || 0,
    grok: totals[3] || 0
  },
  analysisTimestamp: new Date().toISOString()
}}];

// Log final workflow status
const consensus = $('Calculate Consensus').first().json;
return [{ json: {
  status: 'completed',
  productId: consensus.productId ? String(consensus.productId) : 'unknown',
  consensusScore: consensus.consensusScore ? Number(consensus.consensusScore) : 0,
  tier: consensus.tier ? String(consensus.tier) : 'unknown',
  callbackSent: true,
  timestamp: new Date().toISOString()
}}];

// Format data for Replit callback endpoint
const data = $input.first().json;
const llmNames = ['Claude Sonnet 4.6', 'GPT-5.4', 'Gemini 2.5 Pro', 'Grok 4.20'];
const llmKeys = ['claude', 'gpt', 'gemini', 'grok'];

const analyses = [];

// Stage 1
for (let i = 0; i < llmKeys.length; i++) {
  const s1 = data.stage1Results && data.stage1Results[llmKeys[i]];
  if (s1 && !s1.error) {
    analyses.push({
      llm: llmNames[i],
      stage: 1,
      scores: s1.scores || {},
      total: Number(s1.total || 0),
      reasoning: s1.reasoning || ''
    });
  }
}

// Stage 2
const s2arr = data.stage2Results || [];
for (let i = 0; i < s2arr.length; i++) {
  const s2 = s2arr[i];
  if (s2 && !s2.error) {
    analyses.push({
      llm: llmNames[i] || ('LLM-' + i),
      stage: 2,
      scores: s2.scores || {},
      total: Number(s2.total || 0),
      reasoning: s2.stage2_reasoning || s2.reasoning || ''
    });
  }
}

return [{ json: {
  secret: $('Validate Input').first().json.callbackSecret || 'glowindex-callback-secret-2024',
  productId: data.productId,
  runId: data.runId || ('n8n-' + Date.now()),
  analyses: analyses,
  // Pass through for reference
  consensusScore: data.consensusScore,
  tier: data.tier
}}];

// Validate required input fields for skincare analysis
// Supports both direct test payloads and Replit trigger-analysis payloads (price vs priceUsd)
const raw = $input.first().json;
const input = raw.body || raw;

// Normalize price field (Replit sends 'price', tests send 'priceUsd')
const priceUsd = input.priceUsd !== undefined ? input.priceUsd : input.price;

const errors = [];
if (!input.productId) errors.push('productId required');
if (!input.productName && !input.name) errors.push('productName required');
if (!input.brand) errors.push('brand required');
if (priceUsd === undefined || priceUsd === null) errors.push('priceUsd required');
if (errors.length > 0) {
  throw new Error('Validation failed: ' + errors.join(', '));
}

return [{ json: {
  productId: String(input.productId),
  productName: String(input.productName || input.name),
  brand: String(input.brand),
